from collections import defaultdict
from math import comb
def LagrangeInversionTriangle(N: int) -> list[list[int]]:
    P = [[defaultdict(int) for _ in range(N + 1)] for _ in range(N + 1)]
    P[0][0][()] = 1
    for n in range(1, N + 1):
        for k in range(1, n + 1):
            acc = P[n][k]
            for j in range(1, n - k + 2):
                bc = comb(n + k - 1, j)
                for part, c in P[n - j][k - 1].items():
                    i = 0
                    while i < len(part) and part[i] >= j: i += 1
                    acc[part[:i] + (j,) + part[i:]] -= bc * c
    triangle = [[1]]
    for n in range(1, N + 1):
        row = [0]
        for k in range(1, n + 1):
            row.extend(c for _, c in sorted(P[n][k].items(), reverse=True))
        triangle.append(row)
    return triangle
print(LagrangeInversionTriangle(10))

